/* ---- Audit logging ---- */
static void audit_log_event(uint32_t task_id, operation_t op, bool granted)
{
	k_mutex_lock(&audit_mutex, K_FOREVER);

	if (audit_index < MAX_AUDIT_ENTRIES) {
		audit_log[audit_index].task_id = task_id;
		audit_log[audit_index].op = op;
		audit_log[audit_index].granted = granted;
		audit_log[audit_index].timestamp = k_uptime_get();
		audit_index++;
	} else {
		/* Wrap around, overwrite oldest */
		memmove(&audit_log[0], &audit_log[1],
			sizeof(audit_entry_t) * (MAX_AUDIT_ENTRIES - 1));
		audit_log[MAX_AUDIT_ENTRIES - 1].task_id = task_id;
		audit_log[MAX_AUDIT_ENTRIES - 1].op = op;
		audit_log[MAX_AUDIT_ENTRIES - 1].granted = granted;
		audit_log[MAX_AUDIT_ENTRIES - 1].timestamp = k_uptime_get();
	}

	k_mutex_unlock(&audit_mutex);
}

/* ---- Privilege checking ---- */
static bool check_privilege(const task_identity_t *identity, operation_t op)
{
	if (identity == NULL) {
		return false;
	}

	if (op >= OP_INVALID) {
		return false;
	}

	uint8_t required = op_required_priv[op];
	bool granted = (identity->privilege_level & required) == required;

	audit_log_event(identity->task_id, op, granted);

	if (!granted) {
		printk("[SECURITY] Task '%s' (id=%u, priv=0x%02x) denied operation %d "
		       "(required=0x%02x)\n",
		       identity->name, identity->task_id,
		       identity->privilege_level, op, required);
	} else {
		printk("[SECURITY] Task '%s' (id=%u) granted operation %d\n",
		       identity->name, identity->task_id, op);
	}

	return granted;
}

/* ---- Safe string copy ---- */
static void safe_strncpy(char *dst, const char *src, size_t dst_size)
{
	if (dst == NULL || src == NULL || dst_size == 0) {
		return;
	}
	strncpy(dst, src, dst_size - 1);
	dst[dst_size - 1] = '\0';
}

/* ---- Flash operations (admin only) ---- */
static int flash_write(const task_identity_t *identity, uint32_t offset,
		       const uint8_t *data, size_t len)
{
	if (!check_privilege(identity, OP_FLASH_WRITE)) {
		return -EACCES;
	}

	if (data == NULL || len == 0) {
		return -EINVAL;
	}

	if (offset >= FLASH_SIM_SIZE || (offset + len) > FLASH_SIM_SIZE) {
		printk("[FLASH] Write out of bounds: offset=%u, len=%zu\n",
		       offset, len);
		return -EINVAL;
	}

	k_mutex_lock(&flash_mutex, K_FOREVER);
	memcpy(&simulated_flash[offset], data, len);
	k_mutex_unlock(&flash_mutex);

	printk("[FLASH] Written %zu bytes at offset %u by '%s'\n",
	       len, offset, identity->name);
	return 0;
}

static int flash_read(const task_identity_t *identity, uint32_t offset,
		      uint8_t *data, size_t len)
{
	if (!check_privilege(identity, OP_FLASH_READ)) {
		return -EACCES;
	}

	if (data == NULL || len == 0) {
		return -EINVAL;
	}

	if (offset >= FLASH_SIM_SIZE || (offset + len) > FLASH_SIM_SIZE) {
		printk("[FLASH] Read out of bounds: offset=%u, len=%zu\n",
		       offset, len);
		return -EINVAL;
	}

	k_mutex_lock(&flash_mutex, K_FOREVER);
	memcpy(data, &simulated_flash[offset], len);
	k_mutex_unlock(&flash_mutex);

	printk("[FLASH] Read %zu bytes at offset %u by '%s'\n",
	       len, offset, identity->name);
	return 0;
}

/* ---- Config operations ---- */
static int config_write(const task_identity_t *identity, const char *key,
			const char *value)
{
	if (!check_privilege(identity, OP_WRITE_CONFIG)) {
		return -EACCES;
	}

	if (key == NULL || value == NULL) {
		return -EINVAL;
	}

	if (strlen(key) == 0 || strlen(key) >= MAX_CONFIG_KEY_LEN) {
		return -EINVAL;
	}

	if (strlen(value) >= MAX_CONFIG_VAL_LEN) {
		return -EINVAL;
	}

	k_mutex_lock(&config_mutex, K_FOREVER);

	/* Check if key already exists */
	int free_slot = -1;
	for (int i = 0; i < MAX_CONFIG_ENTRIES; i++) {
		if (system_config[i].in_use &&
		    strncmp(system_config[i].key, key, MAX_CONFIG_KEY_LEN) == 0) {
			safe_strncpy(system_config[i].value, value,
				     MAX_CONFIG_VAL_LEN);
			k_mutex_unlock(&config_mutex);
			printk("[CONFIG] Updated '%s' = '%s' by '%s'\n",
			       key, value, identity->name);
			return 0;
		}
		if (!system_config[i].in_use && free_slot < 0) {
			free_slot = i;
		}
	}

	if (free_slot < 0) {
		k_mutex_unlock(&config_mutex);
		printk("[CONFIG] No free config slots\n");
		return -ENOMEM;
	}

	safe_strncpy(system_config[free_slot].key, key, MAX_CONFIG_KEY_LEN);
	safe_strncpy(system_config[free_slot].value, value, MAX_CONFIG_VAL_LEN);
	system_config[free_slot].in_use = true;

	k_mutex_unlock(&config_mutex);

	printk("[CONFIG] Set '%s' = '%s' by '%s'\n",
	       key, value, identity->name);
	return 0;
}

static int config_read(const task_identity_t *identity, const char *key,
		       char *value, size_t value_size)
{
	if (!check_privilege(identity, OP_READ_CONFIG)) {
		return -EACCES;
	}

	if (key == NULL || value == NULL || value_size == 0) {
		return -EINVAL;
	}

	if (strlen(key) == 0 || strlen(key) >= MAX_CONFIG_KEY_LEN) {
		return -EINVAL;
	}

	k_mutex_lock(&config_mutex, K_FOREVER);

	for (int i = 0; i < MAX_CONFIG_ENTRIES; i++) {
		if (system_config[i].in_use &&
		    strncmp(system_config[i].key, key, MAX_CONFIG_KEY_LEN) == 0) {
			safe_strncpy(value, system_config[i].value, value_size);
			k_mutex_unlock(&config_mutex);
			printk("[CONFIG] Read '%s' = '%s' by '%s'\n",
			       key, value, identity->name);
			return 0;
		}
	}

	k_mutex_unlock(&config_mutex);
	printk("[CONFIG] Key '%s' not found\n", key);
	return -ENOENT;
}

/* ---- Request queue management ---- */
static int submit_request(operation_request_t *req)
{
	if (req == NULL) {
		return -EINVAL;
	}

	k_mutex_lock(&request_mutex, K_FOREVER);

	int slot = -1;
	for (int i = 0; i < MAX_PENDING_REQUESTS; i++) {
		if (!request_queue[i].pending && !request_queue[i].completed) {
			slot = i;
			break;
		}
	}

	if (slot < 0) {
		k_mutex_unlock(&request_mutex);
		printk("[REQUEST] Queue full, request rejected\n");
		return -ENOMEM;
	}

	memcpy(&request_queue[slot], req, sizeof(operation_request_t));
	request_queue[slot].pending = true;
	request_queue[slot].completed = false;
	request_queue[slot].result = -EINPROGRESS;

	k_mutex_unlock(&request_mutex);

	/* Signal admin that a request is available */
	k_sem_give(&request_available_sem);

	/* Wait for completion */
	if (k_sem_take(&request_complete_sem, K_MSEC(5000)) != 0) {
		printk("[REQUEST] Timeout waiting for admin to process request\n");
		k_mutex_lock(&request_mutex, K_FOREVER);
		request_queue[slot].pending = false;
		request_queue[slot].completed = false;
		k_mutex_unlock(&request_mutex);
		return -ETIMEDOUT;
	}

	k_mutex_lock(&request_mutex, K_FOREVER);
	int result = request_queue[slot].result;

	/* Copy back any read data */
	if (req->op == OP_READ_CONFIG) {
		safe_strncpy(req->value, request_queue[slot].value,
			     MAX_CONFIG_VAL_LEN);
	} else if (req->op == OP_FLASH_READ) {
		size_t copy_len = request_queue[slot].flash_data_len;
		if (copy_len > sizeof(req->flash_data)) {
			copy_len = sizeof(req->flash_data);
		}
		memcpy(req->flash_data, request_queue[slot].flash_data, copy_len);
		req->flash_data_len = copy_len;
	}

	/* Clear the slot */
	memset(&request_queue[slot], 0, sizeof(operation_request_t));

	k_mutex_unlock(&request_mutex);

	return result;
}

/* ---- Admin task ---- */
static void admin_task(void *p1, void *p2, void *p3)
{
	ARG_UNUSED(p1);
	ARG_UNUSED(p2);
	ARG_UNUSED(p3);

	printk("[ADMIN] Admin task started (priv=0x%02x)\n",
	       admin_identity.privilege_level);

	/* Initialize some default config */
	config_write(&admin_identity, "system.name", "zephyr-embedded");
	config_write(&admin_identity, "system.version", "1.0.0");
	config_write(&admin_identity, "security.level", "high");

	/* Write initial flash data */
	const uint8_t init_data[] = {0xDE, 0xAD, 0xBE, 0xEF};
	flash_write(&admin_identity, 0, init_data, sizeof(init_data));

	while (1) {
		/* Wait for a request from user task */
		if (k_sem_take(&request_available_sem, K_MSEC(1000)) != 0) {
			/* No request, continue */
			continue;
		}

		k_mutex_lock(&request_mutex, K_FOREVER);

		/* Find the pending request */
		int found = -1;
		for (int i = 0; i < MAX_PENDING_REQUESTS; i++) {
			if (request_queue[i].pending && !request_queue[i].completed) {
				found = i;
				break;
			}
		}

		if (found < 0) {
			k_mutex_unlock(&request_mutex);
			continue;
		}

		operation_request_t *req = &request_queue[found];
		printk("[ADMIN] Processing request: op=%d from task_id=%u\n",
		       req->op, req->requester_id);

		/* Validate the operation type */
		if (req->op >= OP_INVALID) {
			req->result = -EINVAL;
			req->completed = true;
			req->pending = false;
			k_mutex_unlock(&request_mutex);
			k_sem_give(&request_complete_sem);
			continue;
		}

		/* Admin executes the operation on behalf of the user,
		 * using admin's own privileges */
		int result = 0;

		switch (req->op) {
		case OP_WRITE_CONFIG:
			k_mutex_unlock(&request_mutex);
			result = config_write(&admin_identity, req->key, req->value);
			k_mutex_lock(&request_mutex, K_FOREVER);
			break;

		case OP_READ_CONFIG: {
			char val_buf[MAX_CONFIG_VAL_LEN];
			k_mutex_unlock(&request_mutex);
			result = config_read(&admin_identity, req->key,
					     val_buf, sizeof(val_buf));
			k_mutex_lock(&request_mutex, K_FOREVER);
			if (result == 0) {
				safe_strncpy(req->value, val_buf,
					     MAX_CONFIG_VAL_LEN);
			}
			break;
		}

		case OP_FLASH_WRITE:
			if (req->flash_data_len > sizeof(req->flash_data)) {
				result = -EINVAL;
			} else {
				k_mutex_unlock(&request_mutex);
				result = flash_write(&admin_identity,
						     req->flash_offset,
						     req->flash_data,
						     req->flash_data_len);
				k_mutex_lock(&request_mutex, K_FOREVER);
			}
			break;

		case OP_FLASH_READ:
			if (req->flash_data_len > sizeof(req->flash_data)) {
				result = -EINVAL;
			} else {
				k_mutex_unlock(&request_mutex);
				result = flash_read(&admin_identity,
						    req->flash_offset,
						    req->flash_data,
						    req->flash_data_len);
				k_mutex_lock(&request_mutex, K_FOREVER);
			}
			break;

		default:
			result = -ENOTSUP;
			break;
		}

		req->result = result;
		req->completed = true;
		req->pending = false;

		k_mutex_unlock(&request_mutex);

		/* Signal the user task that the request is complete */
		k_sem_give(&request_complete_sem);
	}
}

