/* ---- Initialization ---- */
static void init_subsystems(void)
{
	k_mutex_init(&flash_mutex);
	k_mutex_init(&config_mutex);
	k_mutex_init(&request_mutex);
	k_mutex_init(&audit_mutex);
	k_sem_init(&request_available_sem, 0, MAX_PENDING_REQUESTS);
	k_sem_init(&request_complete_sem, 0, 1);

	memset(simulated_flash, 0xFF, sizeof(simulated_flash));
	memset(system_config, 0, sizeof(system_config));
	memset(request_queue, 0, sizeof(request_queue));
	memset(audit_log, 0, sizeof(audit_log));
	audit_index = 0;

	/* Setup admin identity: full privileges */
	admin_identity.task_id = 1;
	admin_identity.privilege_level = PRIV_READ | PRIV_WRITE |
					 PRIV_ADMIN | PRIV_FLASH;
	safe_strncpy(admin_identity.name, "admin", sizeof(admin_identity.name));

	/* Setup user identity: read-only */
	user_identity.task_id = 2;
	user_identity.privilege_level = PRIV_READ;
	safe_strncpy(user_identity.name, "user", sizeof(user_identity.name));
}

int main(void)
{
	printk("=== Embedded Permission System Starting ===\n");

	init_subsystems();

	/* Create admin task with higher priority */
	k_thread_create(&admin_thread_data, admin_stack,
			K_THREAD_STACK_SIZEOF(admin_stack),
			admin_task, NULL, NULL, NULL,
			5, 0, K_NO_WAIT);
	k_thread_name_set(&admin_thread_data, "admin_task");

	/* Create user task with lower priority */
	k_thread_create(&user_thread_data, user_stack,
			K_THREAD_STACK_SIZEOF(user_stack),
			user_task, NULL, NULL, NULL,
			7, 0, K_NO_WAIT);
	k_thread_name_set(&user_thread_data, "user_task");

	return 0;
}